const currentData = isTestEnvironment.value ? fetchConfigBackupFilesEnv.data : fetchConfigBackupFiles.data;
const cutoffTime = rollbackConfigSelectDateTime.value; 

if (cutoffTime === "") {
  filteredConfigBackupData.setValue([]);
  selectedBackupFileLocation.setValue(null);
  return;
}

// Filter and sort objects based on LastModified time
const closestFile = currentData
  .filter(file => new Date(file.LastModified[0]) > new Date(cutoffTime))
  .sort((a, b) => new Date(a.LastModified[0]) - new Date(b.LastModified[0]))[0];

// Set the closest file to the filteredConfigBackupData
if (closestFile) {
  filteredConfigBackupData.setValue([closestFile]);
  selectedBackupFileLocation.setValue(closestFile.Key[0]);
} else {
  filteredConfigBackupData.setValue([]);
  selectedBackupFileLocation.setValue(null);
}
